336	/// Run a fixture: setup hook → cases → teardown hook (finally-shaped).
337	///
338	/// Expects the invocation context to already be installed in the thread-local
339	/// (via `rbtdrc_set_context`); setup/teardown access ctx via that channel.
340	///
341	/// Setup failure short-circuits cases but still invokes teardown. Teardown
342	/// errors are surfaced as warnings via stderr; the function never panics on
343	/// teardown failure.
344	pub fn rbtdre_run_fixture(
345	    fixture: &'static rbtdre_Fixture,
346	    colors: &rbtdre_Colors,
347	    root_temp: &Path,
348	) -> Result<rbtdre_RunResult, String> {
349	    let setup_result = match fixture.setup {
350	        Some(f) => f(),
351	        None => Ok(()),
352	    };
353	
354	    let run_result = match setup_result {
355	        Ok(()) => {
356	            let fail_fast = rbtdre_resolve_fail_fast(fixture.disposition, false)
357	                .expect("disposition-default mode never fails policy resolution");
358	            rbtdre_run_cases(fixture.cases, colors, fail_fast, root_temp)
359	        }
360	        Err(msg) => Err(format!("rbtd: fixture '{}' setup failed: {}", fixture.name, msg)),
361	    };
362	
363	    if let Some(f) = fixture.teardown {
364	        f();
365	    }
366	
367	    run_result
368	}
369	
370	/// Run a single case without charge/quench lifecycle.
371	pub fn rbtdre_run_single_case(
372	    case: &rbtdre_Case,
373	    colors: &rbtdre_Colors,
374	    root_temp: &Path,
375	) -> Result<rbtdre_RunResult, String> {
376	    let case_dir = root_temp.join(case.name);
377	    std::fs::create_dir_all(&case_dir)
378	        .map_err(|e| format!("rbtd: failed to create case dir '{}': {}", case.name, e))?;
379	
380	    let verdict = rbtdre_run_with_heartbeat(case, &case_dir);
381	    rbtdre_write_trace(&case_dir, case.name, &verdict);
382	
383	    let (passed, failed, skipped) = match &verdict {
384	        rbtdre_Verdict::Pass => {
385	            crate::rbtdrg_info_now!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
386	            (1, 0, 0)
387	        }
388	        rbtdre_Verdict::Fail(_) => {
389	            crate::rbtdrg_info_now!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
390	            (0, 1, 0)
391	        }
392	        rbtdre_Verdict::Skip(_) => {
393	            crate::rbtdrg_info_now!("{}SKIPPED:{} {}", colors.yellow, colors.reset, case.name);
394	            (0, 0, 1)
395	        }
396	    };
397	
398	    Ok(rbtdre_RunResult {
399	        passed,
400	        failed,
401	        skipped,
402	        temp_dir: root_temp.to_path_buf(),
403	    })
404	}
